}
printf("String after editing: %s\n", source);
return (0);
}
char * deleted(char *source, int index, int n) {
char rest_str[MAX_LEN];
if (strlen(source) <= index + n) {
source[index] = '\0';
}
else {
strcpy(rest_str, &source[index + n]);
_____A_____;
}
return (source);
}
